from spyne import Application, rpc, ServiceBase, Integer, Unicode, String
from spyne.protocol.soap import Soap11
from spyne.server.wsgi import WsgiApplication
from spyne.model.primitive import Float
from spyne.error import ResourceNotFoundError
from spyne.util.simple_cms import SimpleCacheManagerMiddleware

class FinancialService(ServiceBase):
    
    balances = {
        "account1": 1000.0,
        "account2": 500.0
    }
    
    account_info = {
        "account1": {"name": "Account One", "currency": "USD"},
        "account2": {"name": "Account Two", "currency": "EUR"}
    }

    @rpc(Unicode, _returns=Float)
    def getBalance(ctx, accountId):
        balance = FinancialService.balances.get(accountId, None)
        if balance is None:
            raise ResourceNotFoundError(f"Account {accountId} not found")
        return balance

    @rpc(Unicode, Unicode, Float, _returns=String)
    def transferFunds(ctx, fromAccount, toAccount, amount):
        if fromAccount not in FinancialService.balances or toAccount not in FinancialService.balances:
            return "One or both accounts not found"
        
        if FinancialService.balances[fromAccount] < amount:
            return "Insufficient funds"

        FinancialService.balances[fromAccount] -= amount
        FinancialService.balances[toAccount] += amount
        return "Transfer completed successfully"

    @rpc(Unicode, _returns=Unicode)
    def getAccountInfo(ctx, accountId):
        info = FinancialService.account_info.get(accountId, None)
        if info is None:
            raise ResourceNotFoundError(f"Account {accountId} not found")
        return str(info)

application = Application([FinancialService],
                          tns='spyne.examples.hello',
                          in_protocol=Soap11(validator='lxml'),
                          out_protocol=Soap11())

application.event_manager.add_listener('method_called', 
                                       SimpleCacheManagerMiddleware.add_cache_header_to_http_response)

wsgi_app = WsgiApplication(application)

if __name__ == '__main__':
    import logging
    from wsgiref.simple_server import make_server
    
    logging.basicConfig(level=logging.INFO)
    logging.getLogger('spyne.protocol.xml').setLevel(logging.DEBUG)
    
    server = make_server('0.0.0.0', 8000, wsgi_app)
    logging.info("listening to http://127.0.0.1:8000")
    logging.info("wsdl is at: http://localhost:8000/?wsdl")
    
    server.serve_forever()